+  // Look for same-predicate fcmps comparing the same operand against FP
+  // constants. If so, simplify to a single fcmp.
+  // For "less-than" predicates (olt, ult, ole, ule):
+  //   or: (x < C1) | (x < C2) --> x < max(C1, C2)
+  //   and: (x < C1) & (x < C2) --> x < min(C1, C2)
+  // For "greater-than" predicates (ogt, ugt, oge, uge):
+  //   or: (x > C1) | (x > C2) --> x > min(C1, C2)
+  //   and: (x > C1) & (x > C2) --> x > max(C1, C2)
+  if (PredL == PredR && LHS0 == RHS0) {
+    switch (PredL) {
+    case FCmpInst::FCMP_OLT: case FCmpInst::FCMP_ULT:
+    case FCmpInst::FCMP_OLE: case FCmpInst::FCMP_ULE:
+    case FCmpInst::FCMP_OGT: case FCmpInst::FCMP_UGT:
+    case FCmpInst::FCMP_OGE: case FCmpInst::FCMP_UGE: {
+      const APFloat *C0, *C1;
+      if (match(LHS1, m_APFloat(C0)) && match(RHS1, m_APFloat(C1))) {
+        bool IsLessThan = (PredL == FCmpInst::FCMP_OLT ||
+                           PredL == FCmpInst::FCMP_ULT ||
+                           PredL == FCmpInst::FCMP_OLE ||
+                           PredL == FCmpInst::FCMP_ULE);
+        APFloat::cmpResult Cmp = C0->compare(*C1);
+        // If the constants are equal, either comparison is fine.
+        if (Cmp == APFloat::cmpEqual)
+          return LHS;
+        if (Cmp == APFloat::cmpUnordered)
+          break;
+        bool UseLHS;
+        if (IsLessThan) {
+          // For or: keep the larger constant. For and: keep the smaller.
+          if (IsAnd)
+            UseLHS = Cmp == APFloat::cmpLessThan;
+          else
+            UseLHS = Cmp == APFloat::cmpGreaterThan;
+        } else {
+          // For or: keep the smaller constant. For and: keep the larger.
+          if (IsAnd)
+            UseLHS = Cmp == APFloat::cmpGreaterThan;
+          else
+            UseLHS = Cmp == APFloat::cmpLessThan;
+        }
+        return UseLHS ? static_cast<Value *>(LHS) : static_cast<Value *>(RHS);
+      }
+      break;
+    }
+    default:
+      break;
+    }
+  }

   return nullptr;
 }
